    vld_o  <= r.VldSr(0);
    last_o <= r.LastSr(0);
    rdy_o  <= ParallelRdy_v;

    -- Apply to record
    r_next <= v;

  end process;
  p_seq : process(clk_i)
  begin
    if rising_edge(clk_i) then
      r <= r_next;
      if rst_i = rst_pol_g then
        r.VldSr <= (others => '0');
      end if;
    end if;
  end process;

end architecture;
